import React, { useState } from 'react';

import ResumeService
from '../services/ResumeService';

function ResumeForm() {

  const [resume, setResume] = useState({

    fullName: '',
    email: '',
    phone: '',

    github: '',
    linkedin: '',
    portfolio: '',

    profileImage: '',

    summary: '',

    skills: [''],
    education: [''],
    experience: [''],
    projects: ['']

  });

  // NORMAL INPUT CHANGE

  const handleChange = (e) => {

    setResume({

      ...resume,

      [e.target.name]: e.target.value

    });
  };

  // IMAGE UPLOAD

  const handleImageUpload = (e) => {

    const file = e.target.files[0];

    if (!file) return;

    // IMAGE SIZE VALIDATION

    if (file.size > 2 * 1024 * 1024) {

      alert(
        'Image size should be less than 2MB'
      );

      return;
    }

    const reader = new FileReader();

    reader.onloadend = () => {

      setResume({

        ...resume,

        profileImage: reader.result

      });
    };

    reader.readAsDataURL(file);
  };

  // AI SUMMARY GENERATION

  const generateAISummary = async () => {

    try {

      const skillsText =
        resume.skills.join(', ');

      const response =
        await ResumeService
          .generateSummary(skillsText);

      setResume({

        ...resume,

        summary: response.data

      });

    } catch (error) {

      console.log(error);

      alert(
        'AI Summary Generation Failed'
      );
    }
  };

  // ARRAY FIELD CHANGE

  const handleArrayChange = (
    index,
    field,
    value
  ) => {

    const updated =
      [...resume[field]];

    updated[index] = value;

    setResume({

      ...resume,

      [field]: updated

    });
  };

  // ADD FIELD

  const addField = (field) => {

    setResume({

      ...resume,

      [field]: [

        ...resume[field],
        ''

      ]

    });
  };

  // REMOVE FIELD

  const removeField = (
    field,
    index
  ) => {

    const updated =
      [...resume[field]];

    updated.splice(index, 1);

    setResume({

      ...resume,

      [field]: updated

    });
  };

  // SUBMIT FORM

  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      const formattedResume = {

        ...resume,

        skills:
          resume.skills.join(', '),

        education:
          resume.education.join('\n'),

        experience:
          resume.experience.join('\n'),

        projects:
          resume.projects.join('\n')

      };

      await ResumeService
        .saveResume(formattedResume);

      alert(
        'Resume Saved Successfully'
      );

      // RESET FORM

      setResume({

        fullName: '',
        email: '',
        phone: '',

        github: '',
        linkedin: '',
        portfolio: '',

        profileImage: '',

        summary: '',

        skills: [''],
        education: [''],
        experience: [''],
        projects: ['']

      });

    } catch (error) {

      console.log(error);

      alert('Error Saving Resume');
    }
  };

  return (

    <div className="container mt-5 mb-5">

      <div className="card shadow p-5">

        <h1 className="text-center mb-5">

          Create Resume

        </h1>

        <form onSubmit={handleSubmit}>

          {/* BASIC DETAILS */}

          <input
            type="text"
            name="fullName"
            value={resume.fullName}
            placeholder="Full Name"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          <input
            type="email"
            name="email"
            value={resume.email}
            placeholder="Email"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          <input
            type="text"
            name="phone"
            value={resume.phone}
            placeholder="Phone"
            className="form-control mb-3"
            onChange={handleChange}
            required
          />

          {/* PROFILE IMAGE */}

          <div className="mb-3">

            <label className="form-label">

              Upload Profile Image

            </label>

            <input
              type="file"
              accept="image/*"
              className="form-control"
              onChange={handleImageUpload}
            />

          </div>

          {/* IMAGE PREVIEW */}

          {
            resume.profileImage && (

              <div
                className="mb-4"
                style={{
                  display: 'flex',
                  justifyContent: 'flex-start'
                }}
              >

                <img
                  src={resume.profileImage}
                  alt="Profile"
                  style={{

                    width: '150px',

                    height: '150px',

                    borderRadius: '50%',

                    objectFit: 'cover',

                    border: '4px solid #0d6efd',

                    boxShadow:
                      '0 4px 10px rgba(0,0,0,0.2)'

                  }}
                />

              </div>
            )
          }

          {/* LINKS */}

          <input
            type="text"
            name="github"
            value={resume.github}
            placeholder="GitHub URL"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="text"
            name="linkedin"
            value={resume.linkedin}
            placeholder="LinkedIn URL"
            className="form-control mb-3"
            onChange={handleChange}
          />

          <input
            type="text"
            name="portfolio"
            value={resume.portfolio}
            placeholder="Portfolio URL"
            className="form-control mb-4"
            onChange={handleChange}
          />

          {/* AI BUTTON */}

          <button
            type="button"
            className="btn btn-dark mb-4"
            onClick={generateAISummary}
          >

            Generate AI Summary

          </button>

          {/* SUMMARY */}

          <h4>Professional Summary</h4>

          <textarea
            name="summary"
            value={resume.summary}
            placeholder="Professional Summary"
            className="form-control mb-4"
            rows="4"
            onChange={handleChange}
          ></textarea>

          {/* SKILLS */}

          <h4>Skills</h4>

          {
            resume.skills.map((skill, index) => (

              <div
                className="d-flex mb-2"
                key={index}
              >

                <input
                  type="text"
                  value={skill}
                  placeholder="Skill"
                  className="form-control me-2"
                  onChange={(e) =>
                    handleArrayChange(
                      index,
                      'skills',
                      e.target.value
                    )
                  }
                />

                <button
                  type="button"
                  className="btn btn-danger"
                  onClick={() =>
                    removeField(
                      'skills',
                      index
                    )
                  }
                >

                  Remove

                </button>

              </div>

            ))
          }

          <button
            type="button"
            className="btn btn-primary mb-4"
            onClick={() =>
              addField('skills')
            }
          >

            Add Skill

          </button>

          {/* SAVE BUTTON */}

          <button
            type="submit"
            className="btn btn-success w-100"
          >

            Save Resume

          </button>

        </form>

      </div>

    </div>
  );
}

export default ResumeForm;
